#!/usr/bin/env node
// bundle-env-keys.js
// reads .env at the repo root on the build machine and emits a tiny script
// (dist/rp-keys.bundled.js) that exposes window.rpBundledKeys to the app
// before rp-module.js loads. on every page load the rp module will then
// prefer those keys over whatever's in localstorage.
//
// supported env var formats:
//   NVIDIA_API_KEY_1, NVIDIA_API_KEY_2, ...  -> joined with commas into
//                                                 window.rpBundledKeys.nvidia
//
// the file is regenerated on every `npm run build`. it always exists in dist/
// (empty stub when there's no .env or no matching keys) so index.html's
// <script src="rp-keys.bundled.js"> never 404s.

const fs = require('fs');
const path = require('path');

function readEnv(envPath) {
    if (!fs.existsSync(envPath)) return {};
    const text = fs.readFileSync(envPath, 'utf8');
    const out = {};
    for (const rawLine of text.split('\n')) {
        // strip comments and skip blanks
        const line = rawLine.replace(/^\s*#.*$/, '').trim();
        if (!line) continue;
        // tolerate "export KEY=value" shell style
        const stripped = line.replace(/^export\s+/, '');
        const m = stripped.match(/^([A-Za-z_][A-Za-z0-9_]*)\s*=\s*(.*)$/);
        if (!m) continue;
        let v = m[2];
        // strip surrounding quotes (single or double)
        if ((v.startsWith('"') && v.endsWith('"')) || (v.startsWith("'") && v.endsWith("'"))) {
            v = v.slice(1, -1);
        }
        out[m[1]] = v;
    }
    return out;
}

const repoRoot = path.resolve(__dirname, '..');
const envPath = path.join(repoRoot, '.env');
const distDir = path.join(repoRoot, 'dist');

const env = readEnv(envPath);

// collect NVIDIA_API_KEY_N keys in numeric order
const nvidiaMatches = [];
const KEY_RE = /^NVIDIA_API_KEY_(\d+)$/;
for (const [k, v] of Object.entries(env)) {
    const m = k.match(KEY_RE);
    if (!m) continue;
    const trimmed = (v || '').trim();
    if (!trimmed) continue;
    nvidiaMatches.push({ idx: parseInt(m[1], 10), value: trimmed });
}
nvidiaMatches.sort((a, b) => a.idx - b.idx);

const bundled = {
    nvidia: nvidiaMatches.map(m => m.value).join(',')
};

fs.mkdirSync(distDir, { recursive: true });

const output =
`// auto-generated by scripts/bundle-env-keys.js - DO NOT COMMIT
// regenerated on every \`npm run build\` from .env on the build machine.
// drop your keys in .env as NVIDIA_API_KEY_1, NVIDIA_API_KEY_2, ... and they
// will be baked into THIS local build only (dist/ is gitignored).
(function () {
    if (typeof window === 'undefined') return;
    window.rpBundledKeys = ${JSON.stringify(bundled, null, 4)};
})();
`;

const outPath = path.join(distDir, 'rp-keys.bundled.js');
fs.writeFileSync(outPath, output);

if (nvidiaMatches.length > 0) {
    console.log(`[bundle-env-keys] wrote ${outPath} (${nvidiaMatches.length} nvidia key${nvidiaMatches.length === 1 ? '' : 's'} bundled)`);
} else {
    console.log(`[bundle-env-keys] wrote empty ${outPath} (no .env or no NVIDIA_API_KEY_* entries found)`);
}
